import equimentRoutes from './equiment'
import technologyRoutes from './technology'
import productsRoutes from './products'
import standardRoutes from './standard'
import studyRoutes from './study'
import meterialRoutes from './meterial'
import electricalRoutes from './electrical'
import Layout from '@/views/layout'

const routes = [
  {
    path: 'equiment',
    name: 'equiment',
    meta: {title: '资产管理', icon: 'el-icon-menu'},
    component: Layout,
    children: equimentRoutes
  },
  {
    path: 'technology',
    name: 'technology',
    meta: {title: '工艺管理', icon: 'el-icon-bangzhu'},
    component: Layout,
    children: technologyRoutes
  },
  {
    path: 'products',
    name: 'product',
    meta: {title: '公司产品', icon: 'el-icon-bank-card'},
    component: Layout,
    children: productsRoutes
  },
  {
    path: 'standard',
    name: 'standard',
    meta: {title: '行业标准', icon: 'el-icon-postcard'},
    component: Layout,
    children: standardRoutes
  },{
    path: 'study',
    name: 'study',
    meta: {title: '办公学习', icon: 'el-icon-reading'},
    component: Layout,
    children: studyRoutes
  },
  {
    path: 'meterial',
    name: 'meterial',
    meta: {title: '物料部件', icon: 'el-icon-orange'},
    component: Layout,
    children: meterialRoutes
  },
  {
    path: 'electrical',
    name: 'electrical',
    meta: {title: '电气基础', icon: 'el-icon-cpu'},
    component: Layout,
    children: electricalRoutes
  }
]

export default routes


