const studyRoutes = [
  {
    path: '/studys/info',
    name: 'studyInfo',
    meta: {title: '英语学习', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/study')
  },
  {
    path: '/studys/maintence',
    name: 'studyMaintence',
    meta: {title: 'Autocad', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/equiment')
  },
  {
    path: '/studys/operation',
    name: 'studyOperation',
    meta: {title: 'MS Office', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/studys/computer',
    name: 'studyComputer',
    meta: {title: '电脑操作', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
  ,
  {
    path: '/studys/safety',
    name: 'studySafety',
    meta: {title: '电子书籍', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
]
export default studyRoutes


