const technologyRoutes = [
  {
    path: '/technologys/info',
    name: 'technologyInfo',
    meta: {title: '文件模板', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/technologys/maintence',
    name: 'technologyMaintence',
    meta: {title: '编码规则', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/technologys/operation',
    name: 'technologyOperation',
    meta: {title: '工艺指导', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  }
]
export default technologyRoutes


