const productsRoutes = [
  {
    path: '/products/map',
    name: 'productInfo',
    meta: {title: '能源管理', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/products/maintence',
    name: 'productMaintence',
    meta: {title: '母线配电', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/products/operation',
    name: 'productOperation',
    meta: {title: '信息安全', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/products/safety',
    name: 'productSafety',
    meta: {title: '工业插头', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
]
export default productsRoutes


