const standardRoutes = [
  {
    path: '/standards/info',
    name: 'standardInfo',
    meta: {title: '组织机构', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/equiment')
  },
  {
    path: '/standards/maintence',
    name: 'standardMaintence',
    meta: {title: '体系标准', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/standards/operation',
    name: 'standardOperation',
    meta: {title: '线规标准', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/standards/plugs',
    name: 'standardPlugs',
    meta: {title: '插头标准', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard/WorldPlug')
  }
  ,
  {
    path: '/standards/skew',
    name: 'standardSkewy',
    meta: {title: '螺丝标准', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
]
export default standardRoutes


