const meterialRoutes = [
  {
    path: '/meterial/info',
    name: 'meterialInfo',
    meta: {title: '端子', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/equiment')
  },
  {
    path: '/meterial/maintence',
    name: 'meterialMaintence',
    meta: {title: '断路器', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/meterial/operation',
    name: 'meterialOperation',
    meta: {title: '线材', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/meterial/safety',
    name: 'meterialafety',
    meta: {title: '指示灯', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  },
  {
    path: '/meterial/safety1',
    name: 'meterialafety1',
    meta: {title: '防雷模块', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
]
export default meterialRoutes


