const equimentsRoutes = [
  {
    path: '/equiments/info',
    name: 'equimentInfo',
    meta: {title: '设备信息', icon: 'el-icon-menu'},
    component: ()=>import('@/views/application/equiment')
  },
  {
    path: '/equiments/maintence',
    name: 'equimentMaintence',
    meta: {title: '设备保养', icon: 'el-icon-bangzhu'},
    component: ()=>import('@/views/application/technology')
  },
  {
    path: '/equiments/operation',
    name: 'equimentOperation',
    meta: {title: '作业指导', icon: 'el-icon-bank-card'},
    component: ()=>import('@/views/application/product')
  },
  {
    path: '/equiments/safety',
    name: 'equimentSafety',
    meta: {title: '安全指导', icon: 'el-icon-postcard'},
    component: ()=>import('@/views/application/standard')
  }
]
export default equimentsRoutes


