import Vue from 'vue'
import Router from 'vue-router'
import routes from './routes/application'

Vue.use(Router)

export default new Router({
  mode: 'history',
  routes: [
    {
      path: '/',
      name: 'appication',
      component: ()=>import('@/views/application'),
      children: routes
    },
    {
      path: '/login',
      name: 'login',
      component: ()=>import('@/views/login')
    },
    {
      path: '/404',
      name: 'page404',
      component: ()=>import('@/views/404')
    }
  ]
})



